UPDATE interaction_comment
SET status = 2, update_time = #{updateTime}
WHERE comment_id = #{commentId} AND status = 1

UPDATE interaction_comment
SET status = 2, update_time = #{updateTime}
WHERE root_id = #{rootId} AND status = 1

UPDATE interaction_comment
