mapper.select:
SELECT comment_id
FROM interaction_comment
WHERE post_id = #{postId}
  AND root_id IS NULL
  AND status = 1

    AND comment_id <> #{pinnedId}


    AND (create_time < #{cursorTime} OR (create_time = #{cursorTime} AND comment_id < #{cursorId}))

ORDER BY create_time DESC, comment_id DESC
LIMIT #{limit}

SELECT comment_id
FROM interaction_comment
WHERE post_id = #{postId}
  AND root_id IS NULL
  AND (status = 1 OR (status = 0 AND user_id = #{viewerId}))

    AND comment_id <> #{pinnedId}


    AND (create_time < #{cursorTime} OR (create_time = #{cursorTime} AND comment_id < #{cursorId}))

ORDER BY create_time DESC, comment_id DESC
LIMIT #{limit}

SELECT comment_id FROM interaction_comment WHERE root_id = #{rootId} AND status = 1
AND (create_time > #{cursorTime} OR (create_time = #{cursorTime} AND comment_id > #{cursorId}))
ORDER BY create_time ASC, comment_id ASC LIMIT #{limit}

SELECT comment_id FROM interaction_comment WHERE root_id = #{rootId} AND (status = 1 OR (status = 0 AND user_id = #{viewerId}))
AND (create_time > #{cursorTime} OR (create_time = #{cursorTime} AND comment_id > #{cursorId}))
ORDER BY create_time ASC, comment_id ASC LIMIT #{limit}

SELECT root_id, comment_id, create_time FROM ( SELECT root_id, comment_id, create_time, ROW_NUMBER() OVER (PARTITION BY root_id ORDER BY create_time ASC, comment_id ASC) AS rn FROM interaction_comment WHERE root_id IN
#{id}
AND (status = 1 OR (status = 0 AND user_id = #{viewerId}))
AND status = 1
) t WHERE rn <= #{limit} ORDER BY root_id ASC, create_time ASC, comment_id ASC

mapper.delete:
DELETE FROM interaction_comment
WHERE status = 2
  AND update_time < #{cutoff}
ORDER BY update_time ASC, comment_id ASC
LIMIT #{limit}
